// Aggregate all data into a comprehensive daily report
const dashboard = $('Dashboard Stats').first().json;
const passive = $('Passive Stats').first().json;
const active = $('Active Stats').first().json;
const anomalyData = $('All Anomalies').first().json;
const trends = $('Traffic Trends (24h)').first().json;
const modelMetrics = $('Model Metrics').first().json;
const history = $('Recent Analyses').first().json;

const today = new Date().toISOString().split('T')[0];

// Build the report
let subject = `📊 NetGuard Daily Security Report - ${today}`;

let body = `# NetGuard Daily Security Report\n`;
body += `**Date:** ${today}\n`;
body += `**Generated:** ${new Date().toISOString()}\n\n`;

// Overall Summary
body += `---\n## 📈 Overall Summary\n\n`;
body += `| Metric | Value |\n|--------|-------|\n`;
body += `| Total Flows | ${dashboard.total_flows || 0} |\n`;
body += `| Total Anomalies | ${dashboard.total_anomalies || 0} |\n`;
body += `| Anomaly Rate | ${dashboard.total_flows > 0 ? ((dashboard.total_anomalies / dashboard.total_flows) * 100).toFixed(1) : 0}% |\n`;
body += `| Avg Risk Score | ${(dashboard.avg_risk_score || 0).toFixed(3)} |\n\n`;

// Passive vs Active Breakdown
body += `## 🔄 Monitoring Mode Breakdown\n\n`;
body += `### Passive (File Uploads)\n`;
body += `- Flows: ${passive.total_flows || 0}\n`;
body += `- Anomalies: ${passive.total_anomalies || 0}\n\n`;
body += `### Active (Live Capture)\n`;
body += `- Flows: ${active.total_flows || 0}\n`;
body += `- Anomalies: ${active.total_anomalies || 0}\n\n`;

// Risk Distribution
const riskDist = dashboard.risk_distribution || {};
body += `## 🎯 Risk Distribution\n\n`;
body += `| Level | Count |\n|-------|-------|\n`;
for (const [level, count] of Object.entries(riskDist)) {
  body += `| ${level} | ${count} |\n`;
}
body += `\n`;

// Attack Distribution
const attackDist = dashboard.attack_distribution || {};
if (Object.keys(attackDist).length > 0) {
  body += `## ⚔️ Attack Distribution\n\n`;
  body += `| Type | Count |\n|------|-------|\n`;
  const sorted = Object.entries(attackDist).sort((a, b) => b[1] - a[1]);
  for (const [type, count] of sorted) {
    body += `| ${type} | ${count} |\n`;
  }
  body += `\n`;
}

// Top Threats
const threats = anomalyData.threats || [];
if (threats.length > 0) {
  body += `## 🚨 Top Threats (by risk)\n\n`;
  body += `| Src IP | Classification | Threat Type | Risk | Level |\n`;
  body += `|--------|---------------|-------------|------|-------|\n`;
  for (const t of threats.slice(0, 15)) {
    body += `| ${t.src_ip || 'N/A'} | ${t.classification || '-'} | ${t.threat_type || '-'} | ${(t.risk_score || 0).toFixed(3)} | ${t.risk_level || '-'} |\n`;
  }
  body += `\n`;
}

// Top IPs
const topSrc = dashboard.top_src_ips || [];
const topDst = dashboard.top_dst_ips || [];
if (topSrc.length > 0) {
  body += `## 🌐 Top Source IPs\n\n`;
  for (const ip of topSrc.slice(0, 10)) {
    body += `- **${ip.ip}**: ${ip.count} flows\n`;
  }
  body += `\n`;
}
if (topDst.length > 0) {
  body += `## 🎯 Top Destination IPs\n\n`;
  for (const ip of topDst.slice(0, 10)) {
    body += `- **${ip.ip}**: ${ip.count} flows\n`;
  }
  body += `\n`;
}

// Model Status
const ms = modelMetrics.model_status || {};
body += `## 🤖 Model Status\n\n`;
body += `- Supervised (RF): ${ms.supervised_loaded ? '✅ Loaded' : '❌ Not loaded'}\n`;
body += `- Unsupervised (IF): ${ms.unsupervised_loaded ? '✅ Loaded' : '❌ Not loaded'}\n`;
body += `- Scaler: ${ms.scaler_loaded ? '✅ Loaded' : '❌ Not loaded'}\n`;

const rfMetrics = (modelMetrics.models || {}).random_forest || {};
if (rfMetrics.accuracy) {
  body += `\n### Random Forest Performance\n`;
  body += `- Accuracy: ${(rfMetrics.accuracy * 100).toFixed(1)}%\n`;
  body += `- F1 Score: ${(rfMetrics.f1_score * 100).toFixed(1)}%\n`;
  body += `- Precision: ${(rfMetrics.precision * 100).toFixed(1)}%\n`;
  body += `- Recall: ${(rfMetrics.recall * 100).toFixed(1)}%\n`;
}
body += `\n`;

// Recent Analyses
const analyses = history.analyses || [];
if (analyses.length > 0) {
  body += `## 📁 Recent Analyses\n\n`;
  body += `| File | Flows | Anomalies | Avg Risk | Time |\n`;
  body += `|------|-------|-----------|----------|------|\n`;
  for (const a of analyses.slice(0, 10)) {
    body += `| ${a.filename || '-'} | ${a.total_flows || 0} | ${a.anomaly_count || 0} | ${(a.avg_risk_score || 0).toFixed(3)} | ${a.uploaded_at || '-'} |\n`;
  }
}

body += `\n---\n*Report generated by NetGuard n8n Automation*\n`;

return [{
  json: {
    subject,
    body,
    date: today,
    summary: {
      total_flows: dashboard.total_flows || 0,
      total_anomalies: dashboard.total_anomalies || 0,
      critical_count: riskDist.Critical || 0,
      high_count: riskDist.High || 0
    }
  }
}];

const data = $input.first().json;
return [{
  json: {
    subject: `🚨 CRITICAL: ${data.summary.critical_count} critical threats in daily report`,
    body: `Critical threats detected in today's analysis. Review the daily report immediately.\n\n${data.body.substring(0, 1500)}`,
    priority: 'high'
  }
}];
